INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3671a84c-c8a1-4b78-ae55-460395041c69',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGL to WebGPU: Migrating Compute Shaders$escape$,
  $escape$WebGPU is poised to replace WebGL, offering improved performance and features like compute shaders. To migrate, update your WebGL context creation to use the WebGPU API, and replace WebGL shader compilation with WebGPU's `device.createShaderModule()`. Note that WebGPU uses a different shading language, WGSL, which is similar to HLSL. When creating a compute pipeline, use `device.createComputePipeline()` and specify the entry point of your compute shader.$escape$,
  $escape$const device = await navigator.gpu.requestDevice();
const shaderModule = device.createShaderModule({
  code: `
    struct Data {
      value: f32
    };
    @group(0) @binding(0)
    var<storage> data: Data;
    @compute
    fn main(@builtin(global_invocation_id) id: vec3<u32>) {
      data.value = f32(id.x);
    }
  `
});
const pipeline = device.createComputePipeline({
  layout: 'auto',
  compute: {
    module: shaderModule,
    entryPoint: 'main'
  }
});$escape$,
  $escape$javascript$escape$,
