INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '36b00c10-2aae-44a1-93e4-97aff8e28c46',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGL — Limitations of OpenGL ES 2.0 and Improvements in WebGL2$escape$,
  $escape$WebGL is based on OpenGL ES 2.0, which has limitations such as a maximum of 16 texture units and limited support for floating-point textures. Additionally, WebGL1 has a fixed pipeline, which can lead to performance issues. WebGL2, on the other hand, is based on OpenGL ES 3.0 and provides several improvements, including support for floating-point textures, vertex array objects, and instanced rendering. WebGL2 also introduces a programmable pipeline, allowing for more flexible and efficient rendering.$escape$,
  $escape$const canvas = document.getElementById('canvas'); const gl = canvas.getContext('webgl2'); gl.createVertexArray(); gl.createBuffer();$escape$,
  $escape$javascript$escape$,
