INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f94f51e0-1963-4b3c-a503-7db86841f09c',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGL Texture Optimization — Leveraging Mipmaps and Texture Compression$escape$,
  $escape$When working with WebGL, optimizing textures is crucial for performance. Mipmaps can significantly reduce texture sampling overhead. To generate mipmaps, use the `gl.generateMipmap()` function after uploading the texture data with `gl.texImage2D()`. Additionally, consider using texture compression formats like `WEBGL_compressed_texture_etc1` or `WEBGL_compressed_texture_astc` to reduce memory usage. For PBR materials, use the `gl.texParameteri()` function to set the `TEXTURE_MIN_FILTER` and `TEXTURE_MAG_FILTER` parameters, ensuring proper mipmap selection and texture filtering.$escape$,
  $escape$gl.texParameteri(gl.TEXTURE_2D, gl.TEXTURE_MIN_FILTER, gl.LINEAR_MIPMAP_LINEAR); gl.generateMipmap(gl.TEXTURE_2D);$escape$,
  $escape$javascript$escape$,
