INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '4cbe27cf-207e-46ae-b67b-922d29c426d7',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGL Debugging — Leveraging RenderDoc, Xcode GPU Frame Capture, and NVIDIA Nsight$escape$,
  $escape$Debugging WebGL graphics can be challenging due to the low-level nature of the API. Tools like RenderDoc, Xcode GPU Frame Capture, and NVIDIA Nsight provide invaluable insights into the rendering pipeline. RenderDoc allows for frame capture and analysis, enabling developers to inspect WebGL state, including vertex and index buffers, shaders, and framebuffer attachments. Xcode GPU Frame Capture provides similar functionality, with a focus on iOS and macOS devices. NVIDIA Nsight offers advanced debugging and profiling capabilities, including GPU trace and frame analysis. By leveraging these tools, developers can identify and fix issues related to WebGL rendering, such as incorrect shader execution, texture sampling, and framebuffer configuration.$escape$,
  NULL,
  NULL,
