INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '3522ff03-d898-46b8-8684-59dc96d9aa26',
  '00000000-0000-0000-0000-000000000001',
  $escape$Metal Command Encoders in WebGL — Optimizing iOS/macOS/visionOS Rendering$escape$,
  $escape$When working with WebGL on iOS, macOS, or visionOS, Metal command encoders play a crucial role in optimizing rendering performance. In WebGL, you can use the `EXT_disjoint_timer_query` extension to measure command encoding time. This extension provides a `METAL_COMMAND_ENCODER` type, which can be used to create a command encoder object. The `METAL_COMMAND_ENCODER` object can then be used to create a command buffer, which is submitted to the Metal API for execution. To leverage Metal command encoders in your WebGL app, ensure you've enabled the `EXT_disjoint_timer_query` extension and created a `METAL_COMMAND_ENCODER` object.$escape$,
  NULL,
  NULL,
