INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'b070f258-9e6d-487b-9ee0-2701c8ae9391',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGL: DirectX D3D12 — A Windows-native Rendering Pipeline$escape$,
  $escape$DirectX 12 (D3D12) is a Windows-native API for building high-performance graphics pipelines. While it's not a WebGL API, it can be used in conjunction with WebGL to accelerate rendering on Windows and Xbox platforms. D3D12's strength lies in its ability to execute shaders in a custom bytecode format called DXIL. When combined with WebGL, developers can create more efficient rendering pipelines. To use D3D12 in a WebGL context, the `WEBGL_depth_texture` extension is required. This extension allows developers to share texture resources between WebGL and D3D12.$escape$,
  NULL,
  NULL,
